async function seed() {
  await mongoose.connect(MONGODB_URI);
  console.log("✅ Connected to MongoDB");

  for (const showData of showsData) {
    let show = await Show.findOne({ slug: showData.slug } as any);
    if (!show) {
      show = await Show.create(showData);
      console.log(`✅ Created show: ${showData.title}`);
    } else {
      console.log(`⏭️  Show already exists: ${showData.title}`);
    }

    const questions = allQuestions[showData.slug];
    if (!questions) { console.log(`⚠️  No questions for: ${showData.title}`); continue; }

    const existing = await Question.countDocuments({ showSlug: showData.slug } as any);
    if (existing >= questions.length) {
      console.log(`⏭️  Questions already seeded for: ${showData.title}`);
      continue;
    }

    const toInsert = questions.map((q: any) => ({ ...q, showId: show._id, showSlug: showData.slug }));
    await (Question as any).insertMany(toInsert);
    console.log(`✅ Seeded ${toInsert.length} questions for: ${showData.title}`);
  }

  await mongoose.disconnect();
  console.log("\n🎉 All done! Database is ready.");
}

seed().catch((err) => { console.error(err); process.exit(1); });